import {
    Box,
    Divider,
    IconButton,
    Stack,
    Typography,
    Button,
    Checkbox,
    ButtonBase,
} from '@mui/material'

import React from 'react'
import Iconify from '../Iconify'
import { useDispatch, useSelector } from 'react-redux'
import { getThumbnail } from '../../utils/convertToLink'
import ImageWithFallback from '../Labs/ImageWithFallback'
import BottomAction from 'src/components/common/BottomAction'
import { useConfirmationModalContext } from 'src/utils/Modal'
import More from 'src/assets/IconSet/More'
import EditIcon from 'src/assets/IconSet/edit'
import ShareIcon from 'src/assets/IconSet/Share'
import RemoveIcon from 'src/assets/IconSet/Delete'
import CopyIcon from 'src/assets/IconSet/CopyLink'
import { useNavigate } from 'react-router'
import { updateFeedback } from 'src/redux/actions/feedback'
import { deleteVideo } from 'src/redux/actions/figgsLibrary'
export default function Videos(props) {
    const videos = useSelector((s) => s.Library.videos)
    const navigate = useNavigate()
    const dispatch = useDispatch()
    const { showConfirmationModal } = useConfirmationModalContext()
    const onChangeSelection = (workout) => {
        let existIndex = props?.selectedWorkout?.findIndex(
            (i) => i._id == workout._id
        )
        let arr = [...props.selectedWorkout]
        if (existIndex > -1) {
            arr.splice(existIndex, 1)
        } else {
            arr.push({
                ...workout,
                media: `https://circled-videos.s3.us-east-1.amazonaws.com/${workout.key}`,
            })
        }

        props.setSelectedWorkout(arr)
    }
    const delettheVideo = (id) => {
        showConfirmationModal(
            'Are you sure?',
            `You are going to delete this video`,
            'Delete'
        ).then((res) => {
            dispatch(
                deleteVideo({
                    _id: id,
                    savedToLibrary: false,
                })
            )
        })
    }
    return (
        <Box
            height={videos.length == 0 ? '100%' : 'auto'}
            display={videos.length == 0 ? 'flex' : 'block'}
            flexDirection={'column'}
            alignItems={'flex-start'}
        >
            {!props?.slectionMode ? (
                <ButtonBase
                    variant="text"
                    color="primary"
                    sx={{
                        color: 'primary.main',
                        my: 1,
                    }}
                    onClick={(e) =>
                        document.getElementById('addvideoinput').click()
                    }
                >
                    <input
                        id="addvideoinput"
                        accept="video/*"
                        type="file"
                        onChange={(e) =>
                            navigate('/library/editvideo', {
                                state: { mode: 'add', file: e.target.files[0] },
                            })
                        }
                        style={{ display: 'none' }}
                    />
                    {/* <Iconify icon="mingcute:add-fill" sx={{ fontSize: 18 }} />
                    &nbsp;{' '} */}
                    <Typography
                        sx={{
                            fontSize: 18,
                            color: 'primary.main',
                        }}
                    >
                        Add video
                    </Typography>
                </ButtonBase>
            ) : null}
            {videos.length == 0 ? (
                <Box
                    flexGrow={1}
                    width={'100%'}
                    flexDirection={'column'}
                    display={'flex'}
                    alignItems={'center'}
                    justifyContent={'center'}
                >
                    <Typography align="center" color={'grey.600'}>
                        No saved videos! <br />
                        Add from phone or workouts.
                    </Typography>
                </Box>
            ) : (
                videos?.map((i, index) => (
                    <VideoCard
                        title={i.title || 'unamed'}
                        id={i._id}
                        url={i.key}
                        onClick={() => {
                            if (props?.slectionMode) return
                            navigate(`/library/editvideo`, {
                                state: {
                                    mode: 'edit',
                                    ...i,
                                },
                            })
                        }}
                        onChangeSelection={() => onChangeSelection(i)}
                        checked={
                            props?.selectedWorkout?.find(
                                (vi) => vi._id == i._id
                            )
                                ? true
                                : false
                        }
                        deleteVideo={() => delettheVideo(i._id)}
                        slectionMode={props?.slectionMode}
                        selectedWorkout={props?.selectedWorkout}
                        setSelectedWorkout={props?.setSelectedWorkout}
                    />
                ))
            )}
        </Box>
    )
}

const VideoCard = ({
    title,
    url,
    onClick,
    slectionMode,
    deleteVideo,
    checked,
    onChangeSelection,
}) => {
    const dispatch = useDispatch()
    const copy = () => {
        if (navigator && navigator.clipboard != undefined) {
            navigator.clipboard.writeText('hrefLink')
        }
        dispatch(
            updateFeedback({
                snackbar: true,
                severity: 'success',
                message: 'Link copied to clipboard',
            })
        )
    }

    return (
        <Box py={2}>
            <Stack
                direction={'row'}
                justifyContent={'space-between'}
                onClick={onClick}
            >
                <Box display={'flex'} alignItems={'center'}>
                    <Box
                        bgcolor={'#f0f0f0'}
                        borderRadius={1}
                        width={100}
                        height={65}
                        mr={1}
                        sx={{ overflow: 'hidden' }}
                    >
                        <ImageWithFallback
                            //onClick={props.onClick}
                            variant="rounded"
                            style={{
                                width: '100%',
                                height: '100%',
                                objectFit: 'cover',
                            }}
                            src={
                                getThumbnail(url, '/') ||
                                '/images/instructor/exerciseImage.png'
                            }
                        />
                    </Box>
                    <Typography sx={{ textTransform: 'capitalize' }}>
                        {title}
                    </Typography>
                </Box>
                {slectionMode ? (
                    <Checkbox
                        color="primary"
                        checked={checked}
                        onChange={onChangeSelection}
                    />
                ) : (
                    <Box onClick={(e) => e.stopPropagation()}>
                        <BottomAction
                            items={[
                                // {
                                //     title: 'Copy link',
                                //     icon: <CopyIcon sx={{ mr: 2 }} />,
                                //     onClick: copy,
                                // },
                                // {
                                //     title: 'Share',
                                //     icon: <ShareIcon sx={{ mr: 2 }} />,
                                // },
                                {
                                    title: 'Edit video',
                                    icon: <EditIcon sx={{ mr: 2 }} />,
                                    onClick: onClick,
                                },
                                {
                                    title: 'Remove',
                                    icon: (
                                        <RemoveIcon
                                            sx={{ mr: 2, color: 'error.main' }}
                                        />
                                    ),
                                    onClick: deleteVideo,
                                    isError: true,
                                },
                            ]}
                            title={title}
                        >
                            <IconButton>
                                <More
                                    sx={{
                                        fontSize: 32,
                                        color: 'text.primary',
                                    }}
                                />
                            </IconButton>
                        </BottomAction>
                    </Box>
                )}
            </Stack>
           
        </Box>
    )
}
